<span class="line">        <span class="token keyword">this</span><span class="token punctuation">.</span>peerConnection<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
